// Alle Feeds parsen (Google Trends RSS, Google News RSS ×2, Hacker News JSON)
const allItems = [];
const inputs = $input.all();

// Hilfsfunktion: XML-Tag-Inhalt extrahieren + CDATA/HTML bereinigen
const getTag = (block, tag) => {
  const open = '<' + tag + '>';
  const close = '</' + tag + '>';
  const s = block.indexOf(open);
  const e = block.indexOf(close);
  if (s === -1 || e === -1) return '';
  let val = block.substring(s + open.length, e);
  if (val.indexOf('CDATA[') !== -1) {
    const cdataStart = val.indexOf('CDATA[') + 6;
    const cdataEnd = val.lastIndexOf(']]>');
    val = cdataEnd !== -1 ? val.substring(cdataStart, cdataEnd) : val.substring(cdataStart);
  }
  return val.replace(/<[^>]+>/g, '').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').trim();
};

// Reihenfolge der Inputs entspricht der Verbindungsreihenfolge:
// 0 = Google Trends DE (RSS), 1 = Google News KI/AI (RSS), 2 = Google News IT/Nischen (RSS), 3 = Hacker News (JSON)
inputs.forEach((input, feedIndex) => {
  const rawData = String(input.json.data || input.json.body || '');

  if (feedIndex === 3) {
    // Hacker News – JSON-Antwort (Algolia API)
    let hn;
    try { hn = JSON.parse(rawData); } catch (e) { return; }
    const hits = Array.isArray(hn.hits) ? hn.hits : [];
    hits.slice(0, 12).forEach(hit => {
      if (!hit.title) return;
      allItems.push({
        category: 'Hacker News / Tech International',
        title: String(hit.title).substring(0, 150),
        description: (hit.points || 0) + ' Punkte · ' + (hit.num_comments || 0) + ' Kommentare',
        link: hit.url || ('https://news.ycombinator.com/item?id=' + hit.objectID),
        pubDate: hit.created_at || ''
      });
    });
  } else if (feedIndex === 0) {
    // Google Trends DE – Trending Searches RSS
    const rawItems = rawData.split('<item>').slice(1, 14);
    rawItems.forEach(block => {
      const title = getTag(block, 'title').substring(0, 150);
      // Zugehörige News zum Trending-Topic extrahieren
      const relatedMatch = block.match(/<ht:news_item_title>([^<]+)<\/ht:news_item_title>/);
      const relatedSnippet = block.match(/<ht:news_item_snippet>([^<]+)<\/ht:news_item_snippet>/);
      let desc = '';
      if (relatedMatch) desc = relatedMatch[1].trim();
      if (relatedSnippet) desc += ' – ' + relatedSnippet[1].trim();
      if (!desc) desc = getTag(block, 'description').substring(0, 300);
      const link = getTag(block, 'link');
      const date = getTag(block, 'pubDate');
      if (title.length > 3) {
        allItems.push({ category: 'Google Trends DE', title, description: desc.substring(0, 300), link, pubDate: date });
      }
    });
  } else {
    // Google News – RSS XML (index 1: KI/AI, index 2: IT/Nischen)
    const category = feedIndex === 1 ? 'KI/AI' : 'IT/Tech/Nischen';
    const rawItems = rawData.split('<item>').slice(1, 14);
    rawItems.forEach(block => {
      const title = getTag(block, 'title').substring(0, 150);
      const desc = getTag(block, 'description').substring(0, 300);
      const link = getTag(block, 'link');
      const date = getTag(block, 'pubDate');
      if (title.length > 10) {
        allItems.push({ category, title, description: desc, link, pubDate: date });
      }
    });
  }
});

const feedText = allItems.map((i, idx) =>
  '[' + i.category + ' #' + (idx + 1) + '] ' + i.title +
  (i.description ? '\nInhalt: ' + i.description : '') +
  '\nURL: ' + i.link +
  '\nDatum: ' + i.pubDate
).join('\n\n---\n\n');

if (allItems.length < 3) {
  throw new Error('Zu wenige Artikel gefunden: ' + allItems.length + '. Bitte Feeds prüfen.');
}

return [{ json: { feedText, itemCount: allItems.length, fetchedAt: new Date().toISOString() } }];

