// Claude-Antwort parsen → 3 separate Items ausgeben
const raw = $input.first().json.content[0].text.trim();

let parsed;
try {
  // JSON aus möglichem Markdown-Block extrahieren
  const jsonMatch = raw.match(/```(?:json)?\s*([\s\S]*?)```/) || raw.match(/(\{[\s\S]*\})/);
  const jsonStr = jsonMatch ? jsonMatch[1].trim() : raw;
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error('Claude hat kein gültiges JSON geliefert. Antwort: ' + raw.substring(0, 300) + ' | Fehler: ' + e.message);
}

const topics = parsed.topics;
if (!Array.isArray(topics) || topics.length !== 3) {
  throw new Error('Erwartet: 3 Themen, erhalten: ' + JSON.stringify(topics).substring(0, 200));
}

// Jedes Thema als eigenes n8n-Item zurückgeben
return topics.map(t => ({
  json: {
    rank: t.rank,
    topic: t.topic,
    summary: t.summary,
    sources: Array.isArray(t.sources) ? t.sources.join('\n') : String(t.sources || ''),
    category: t.category,
    seo_keywords: Array.isArray(t.seo_keywords) ? t.seo_keywords.join(', ') : String(t.seo_keywords || ''),
    today: new Date().toISOString().split('T')[0]
  }
}));

// OpenAI-Antwort parsen, Markdown aufbereiten, Slug generieren
const response = $input.first().json;

if (!response.choices || !response.choices[0]) {
  throw new Error('OpenAI Fehler: ' + JSON.stringify(response).substring(0, 300));
}

const raw = response.choices[0].message.content.trim();

// Markdown aus Code-Block extrahieren falls vorhanden
let markdown = raw;
const fenceMatch = raw.match(/```(?:markdown)?\n?([\s\S]+?)\n?```/);
if (fenceMatch) markdown = fenceMatch[1].trim();

// Frontmatter-Felder lesen
const titleMatch = markdown.match(/^title:\s*"([^"]+)"/m);
const title = titleMatch ? titleMatch[1] : 'tech-blog-post-' + Date.now();

// SEO-freundlichen Slug generieren
const slug = title
  .toLowerCase()
  .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss')
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .replace(/^-|-$/g, '')
  .substring(0, 65);

const filename = slug + '.md';
const contentB64 = Buffer.from(markdown).toString('base64');

// Ursprüngliche Topic-Daten aus dem vorherigen Schritt weiterleiten
const prev = $('Themen in Items aufteilen').item.json;

return [{ json: {
  rank: prev.rank,
  topic: prev.topic,
  category: prev.category,
  filename,
  slug,
  contentB64,
  markdown,
  tokensUsed: response.usage ? response.usage.total_tokens : 0
} }];

// Veröffentlichungszeitpunkt berechnen
// rank 0 → sofort
// rank 1 → morgen, 16–22 Uhr, zufällige Minute
// rank 2 → übermorgen, 16–22 Uhr, zufällige Minute
const rank = $json.rank || 0;
let publishAt;

if (rank === 0) {
  // Sofort veröffentlichen
  publishAt = new Date().toISOString();
} else {
  const d = new Date();
  d.setDate(d.getDate() + rank); // Tag +1 oder +2
  const hour = 16 + Math.floor(Math.random() * 7); // 16, 17, 18, 19, 20, 21 oder 22 Uhr
  const minute = Math.floor(Math.random() * 60);
  d.setHours(hour, minute, 0, 0);
  publishAt = d.toISOString();
}

return [{ json: { ...$json, publishAt, publishMode: rank === 0 ? 'immediate' : 'scheduled' } }];

const statusCode = $response?.statusCode || $input.first().json?.status;
const success = statusCode === 204 || statusCode === 200;
const item = $input.first().json;

const logEntry = {
  status: success ? 'published' : 'error',
  rank: item.rank,
  publishMode: item.publishMode,
  publishAt: item.publishAt,
  filename: item.filename,
  slug: item.slug,
  category: item.category,
  tokensUsed: item.tokensUsed,
  url: 'https://www.scholz-cloud.de/blog/' + item.slug + '/'
};

if (success) {
  console.log('[Blog Publisher] Veröffentlicht:', JSON.stringify(logEntry));
} else {
  console.error('[Blog Publisher] Fehler:', JSON.stringify(logEntry));
}

return [{ json: logEntry }];
